alue="stripe" checked>                    <label class="form-check-label" for="payment_method">Credit Card (Stripe)</label>                </div>                <!--<div class="form-check mb-2">                    <input class="form-check-input" type="radio" name="payment_method" id="orderWithoutPay" value="order_without_pay" >                    <label class="form-check-label" for="orderWithoutPay">Order without pay</label>                </div>-->            </div>            <div class="col-12 mb-2">                <div class="form-check">                    <div id="card-element"></div>                    <div id="card-errors" role="alert"></div>                </div>            </div>                        <div class="d-flex justify-content-between">            <button type="button" onclick="bookWithoutPayment()" class="btn btn-dark w-15" id="submit-button">Book without pay</button>            <p class="text-muted mt-3 text-center" id="info-secured">All your information is 100% secured.</p>            </div>            <div id="subitMessage"></div>          </form>        </div></div></section><script>        // Initialize Stripe with your Publishable Key        const stripe = Stripe("{{ config('services.stripe.key') }}");        const elements = stripe.elements();        // Create an instance of the card element        const card = elements.create("card");        card.mount("#card-element");        // Handle real-time validation errors        card.addEventListener("change", function(event) {            const displayError = document.getElementById("card-errors");            if (event.error) {                displayError.textContent = event.error.message;            } else {                displayError.textContent = "";            }        });        // Handle form submission        const form = document.getElementById("payment-form");        form.addEventListener("submit", async function(event) {            event.preventDefault();            const { paymentMethod, error } = await stripe.createPaymentMethod({                type: "card",                card: card,                billing_details: {                    name: document.getElementById("billing_first_name").value,                    email: document.getElementById("billing_email").value,                                    },            });            if (error) {                document.getElementById("card-errors").textContent = error.message;            } else {                //alert("Payment successful! Payment Method ID: " + paymentMethod.id);                // Send the Payment Method ID to the server for further processing                fetch("/process-payment", {                    method: "POST",                    headers: {                        "Content-Type": "application/json",                        "X-CSRF-TOKEN": "{{ csrf_token() }}"                    },                    body: JSON.stringify({                        payment_method_id: paymentMethod.id,                        amount: document.getElementById("order_amount").value,                        billing_first_name: document.getElementById("billing_first_name").value,                        billing_last_name: document.getElementById("billing_last_name").value,                        billing_phone: document.getElementById("billing_phone").value,                        billing_email: document.getElementById("billing_email").value,                        billing_company: document.getElementById("billing_company").value,                        billing_country: document.getElementById("billing_country").value,                        billing_address_1: document.getElementById("billing_address_1").value,                        billing_city: document.getElementById("billing_city").value,                        billing_postcode: document.getElementById("billing_postcode").value,                        order_amount: document.getElementById("order_amount").value,                        payment_method: document.querySelector('input[name="payment_method"]:checked').value                    })                })                .then(response => response.json())                .then(data => {                    if (data.error) {                        alert("Payment failed: " + data.error);                    } else {                        console.log(data);                        if(data.paymentIntent==0){                            window.location.href = "{{ route('shop') }}"; // Redirect on success                        }else{                            window.location.href = "{{ route('order-success') }}"; // Redirect on success                        }                        //alert("Payment successful!");                    }                });            }        });    </script><script>        function bookWithoutPayment() {                var first_name = $('#first_name').val();        var last_name = $('#last_name').val();        var email = $('#email').val();        var mobile = $('#mobile').val();                if (first_name == '') {                        $('#first_name').focus();            //alert('Enter first name.');            return false;        } else {        }                if (email == '') {            $('#email').focus();            //alert('Enter email.');            return false;        } else {        }                if (mobile == '') {            $('#mobile').focus();            //alert('Enter mobile.');            return false;        } else {        }                               return $.ajax({            url: "{{ route('bookWithoutPayment') }}",            type: 'POST',            data: {                "_token": "{{ csrf_token() }}",                first_name: first_name,                last_name: last_name,                email: email,                mobile: mobile,                            },            beforeSend: function(res) {                //$('#state').html('<option value="">Loading...</option>');            },            success: function(res) {                //alert(res.status);                 if(res.status=='success'){                    // $('#first_name').val('');                    // $('#last_name').val('');                    // $('#email').val('');                    // $('#mobile').val('');                                        window.location.href = 'booking-success';                    $('#subitMessage').html('<div id="alertMessage" class="alert alert-success" role="alert">Form submitted successfully!</div>');                }else{                    $('#subitMessage').html('<div id="alertMessage" class="alert alert-danger" role="alert">Something went wrong!</div>');                  }                            }        })    }    </script> @endsection